#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int activities;
        char origin[10];
        scanf("%d %s", &activities, origin);
        int totalLaddus = 0;
        for (int i = 0; i < activities; i++) {
            char activity[20];
            scanf("%s", activity);
            if (strcmp(activity, "CONTEST_WON") == 0) {
                int rank;
                scanf("%d", &rank);
                totalLaddus += 300 + (rank <= 20 ? 20 - rank : 0);
            } else if (strcmp(activity, "TOP_CONTRIBUTOR") == 0) {
                totalLaddus += 300;
            } else if (strcmp(activity, "BUG_FOUND") == 0) {
                int severity;
                scanf("%d", &severity);
                totalLaddus += severity;
            } else if (strcmp(activity, "CONTEST_HOSTED") == 0) {
                totalLaddus += 50;
            }
        }
        int minLaddusPerMonth = strcmp(origin, "INDIAN") == 0 ? 200 : 400;
        printf("%d\n", totalLaddus / minLaddusPerMonth);
    }
    return 0;
}

